class FileSystem:
    def __init__(self):
        self.root = {"dirs": {}, "files": {}}
    def _find(self, path):
        node = self.root
        if path == "/": return node, "/"
        parts = path.split("/")[1:]
        for p in parts[:-1]: node = node["dirs"][p]
        return node, parts[-1]
    def ls(self, path):
        node, name = self._find(path)
        if name == "/": return sorted(list(node["dirs"].keys()) + list(node["files"].keys()))
        if name in node["files"]: return [name]
        node = node["dirs"][name]
        return sorted(list(node["dirs"].keys()) + list(node["files"].keys()))
    def mkdir(self, path):
        node = self.root
        for p in path.split("/")[1:]:
            if p not in node["dirs"]: node["dirs"][p] = {"dirs": {}, "files": {}}
            node = node["dirs"][p]
    def addContentToFile(self, filePath, content):
        node, name = self._find(filePath)
        node["files"][name] = node["files"].get(name, "") + content
    def readContentFromFile(self, filePath):
        node, name = self._find(filePath)
        return node["files"][name]

